def ensure_dir(path): os.makedirs(path, exist_ok=True)

def rolling_mean(x, k):
    if not k or k <= 1: return x
    k = int(min(k, len(x)))
    if k <= 1: return x
    w = np.ones(k, dtype=float) / k
    return np.convolve(x, w, mode='valid')  # 左对齐：窗口 [t, t+k-1] 的平均

def smooth_for_plot(y, k):
    """
    返回 (x, y_smooth)。使用 rolling_mean(valid) 时，为了对齐原始步号，
    x 从 (k-1) 开始，即绘制在窗口的末端位置。
    """
    if not k or k <= 1 or len(y) < k:
        return np.arange(len(y)), y
    y_s = rolling_mean(y, k)
    x = np.arange(k-1, k-1 + len(y_s))
    return x, y_s

def find_scenarios(root):
    out = []
    for p in glob.glob(os.path.join(root, "scenario_*")):
        try: out.append(int(os.path.basename(p).split("_")[1]))
        except: pass
    return sorted(out)

def find_algos(root, scenario):
    base = os.path.join(root, f"scenario_{scenario}")
    if not os.path.isdir(base): return []
    return sorted([d for d in os.listdir(base) if os.path.isdir(os.path.join(base, d))])

def find_runs(root, scenario, algo):
    base = os.path.join(root, f"scenario_{scenario}", algo)
    runs = set()
    for pat in ["results_*.npz", "history_*.npz", "*_run*_metrics.csv"]:
        for f in glob.glob(os.path.join(base, pat)):
            stem = os.path.splitext(os.path.basename(f))[0]
            r = _parse_run_from_stem(stem)
            if r is not None:
                runs.add(r)
    return sorted(runs)

def _parse_run_from_stem(stem: str):
    # new pattern: history_run{r}_env{e} / results_run{r}_env{e}
    m = re.search(r"(?:^|_)(?:history|results)_run(\d+)_env\d+(?:$|_)", stem)
    if m:
        return int(m.group(1))
    # old pattern: history_{r} / results_{r}
    m = re.search(r"(?:^|_)(?:history|results)_(\d+)(?:$|_)", stem)
    if m:
        return int(m.group(1))
    # csv pattern: Algo_run{r}_metrics
    m = re.search(r"_run(\d+)_metrics$", stem)
    if m:
        return int(m.group(1))
    return None

def load_npz_by_run_envs(root, scenario, algo, run):
    base = os.path.join(root, f"scenario_{scenario}", algo)
    files = []
    for pat in [f"results_run{run}_env*.npz", f"history_run{run}_env*.npz"]:
        files.extend(sorted(glob.glob(os.path.join(base, pat))))
    if not files:
        for fname in [f"results_{run}.npz", f"history_{run}.npz"]:
            path = os.path.join(base, fname)
            if os.path.isfile(path):
                files.append(path)
                break
        if not files:
            for pat in [f"results_{run}*.npz", f"history_{run}*.npz"]:
                files = sorted(glob.glob(os.path.join(base, pat)))
                if files:
                    break
    return [np.load(p) for p in files], files

# ---------- 读取训练期 CSV（由 TBMetricsCallback 生成）的函数 ----------
def load_csv_metrics_by_run(root, scenario, algo, run):
    """
    查找 {algo}_run{run}_metrics.csv 或 *run{run}_metrics.csv
    返回 dict: {
      'tb_steps': np.array([...]),
      'rnn_epstarts_curve': np.array([...]),
      'rnn_seq_len_curve': np.array([...]),
      'env_viol_mean_curve': np.array([...]) | None,
      'env_prio_viol_curve': np.array([...]) | None,
      'env_prbs_mean_curve': np.array([...]) | None,
      '_csv_path': '...'
    } 或 None
    """
    base = os.path.join(root, f"scenario_{scenario}", algo)
    cands = [
        os.path.join(base, f"{algo}_run{run}_metrics.csv"),
        *glob.glob(os.path.join(base, f"*run{run}_metrics.csv")),
        *glob.glob(os.path.join(base, f"*_{run}_metrics.csv")),
    ]
    cands = [p for p in cands if os.path.isfile(p)]
    if not cands:
        return None

    p = sorted(cands)[0]
    steps, epstarts, seqlen, viol, pviol, prbs = [], [], [], [], [], []
    with open(p, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        # timesteps, env_viol_mean, env_prio_viol_mean, env_prbs_mean, rnn_epstart_frac, rnn_avg_seq_len
        for row in reader:
            def _get(name):
                return row.get(name, "") if row.get(name, "") != "" else None
            def _to_float(x):
                try: return float(x)
                except: return None

            steps.append(_to_float(_get("timesteps")))
            viol.append(_to_float(_get("env_viol_mean")))
            pviol.append(_to_float(_get("env_prio_viol_mean")))
            prbs.append(_to_float(_get("env_prbs_mean")))
            epstarts.append(_to_float(_get("rnn_epstart_frac")))
            seqlen.append(_to_float(_get("rnn_avg_seq_len")))

    def _clean(xs):
        xs = np.array([x for x in xs if x is not None], dtype=float)
        return xs if xs.size > 0 else None

    out = {
        'tb_steps': _clean(steps),
        'rnn_epstarts_curve': _clean(epstarts),
        'rnn_seq_len_curve': _clean(seqlen),
        'env_viol_mean_curve': _clean(viol),
        'env_prio_viol_curve': _clean(pviol),
        'env_prbs_mean_curve': _clean(prbs),
        '_csv_path': p
    }
    # 若关键字段都缺，返回 None
    if out['tb_steps'] is None or (out['rnn_epstarts_curve'] is None and out['rnn_seq_len_curve'] is None):
        return None
    return out

def _merge_aux_csv_into_ts(ts, aux_csv):
    if aux_csv is None:
        return ts
    if aux_csv.get('tb_steps') is not None:
        ts['tb_steps'] = aux_csv['tb_steps']
    for k_src, k_dst in [
        ('rnn_epstarts_curve', 'rnn_epstarts_curve'),
        ('rnn_seq_len_curve',  'rnn_seq_len_curve'),
        ('env_viol_mean_curve','env_viol_curve_tb'),
        ('env_prio_viol_curve','env_prio_viol_curve_tb'),
        ('env_prbs_mean_curve','env_prbs_curve_tb'),
    ]:
        if aux_csv.get(k_src) is not None:
            ts[k_dst] = aux_csv[k_src]
    ts['lstm_metrics_source'] = aux_csv.get('_csv_path')
    return ts

def _get_first_key_case_insensitive(data, candidates):
    keys = list(data.files)
    lower_map = {k.lower(): k for k in keys}
    for c in candidates:
        k = lower_map.get(c.lower())
        if k is not None:
            return k
    return None

def _to_violation_indicator(ts):
    if 'violation' in ts:
        v = ts['violation'].astype(np.float64)
        return (v > 0).astype(np.float64)
    if 'SLA' in ts:
        s = ts['SLA'].astype(np.float64)
        return (s <= 0).astype(np.float64)
    return None

# ---------- 新增：读取 resources 的函数（只看 resources 字段） ----------
def _extract_resources_series_from_npz(data):
    """
    从 npz 中读取 case-insensitive 'resources'，直接返回该序列。
    """
    k_res = _get_first_key_case_insensitive(data, ['resources'])
    if k_res is not None:
        try:
            return data[k_res].astype(np.float64), f"resources:{k_res}"
        except Exception:
            pass
    return None, "none"

# ---------- 修改：读取“每步 allocated_prbs 总量”的函数 ----------
def _extract_alloc_sum_series_from_npz(data):
    """
    只从 case-insensitive 'allocated_prbs' 读取：
      - 若为二维/更高维数组：[T,S,...] → 每步对最后一维求和
      - 若为一维且 dtype=object（list-of-arrays）：对每个元素 np.sum(...)
      - 若为一维数值数组：当作已是每步总量返回
    不再回退到 'resources'。
    返回: (series: np.ndarray or None, source: str)
    """
    k_alloc = _get_first_key_case_insensitive(data, ['allocated_prbs'])
    if k_alloc is not None:
        arr = data[k_alloc]
        try:
            if isinstance(arr, np.ndarray):
                if arr.ndim >= 2:
                    sums = arr.reshape(arr.shape[0], -1).sum(axis=1).astype(np.float64)
                    return sums, f"allocated_prbs:{k_alloc}[2D]"
                elif arr.ndim == 1:
                    if arr.dtype == object:
                        sums = np.array([float(np.sum(np.asarray(x))) for x in arr], dtype=np.float64)
                        return sums, f"allocated_prbs:{k_alloc}[object-1D]"
                    else:
                        return arr.astype(np.float64), f"allocated_prbs:{k_alloc}[1D]"
        except Exception:
            pass
        try:
            sums = np.array([float(np.sum(np.asarray(x))) for x in arr], dtype=np.float64)
            return sums, f"allocated_prbs:{k_alloc}[iter]"
        except Exception:
            pass

    return None, "none"

def summarize_single_run(data, aux_csv=None):
    ts = {}

    # 常规序列（reward / violation）
    for name, aliases in {
        'reward':    ['reward'],
        'violation': ['violation','violations','total_violations'],
    }.items():
        k = _get_first_key_case_insensitive(data, aliases)
        if k is not None: ts[name] = data[k].astype(np.float64)

    # ★ 资源：从 resources 字段读取（wrapper 保存的 sum_prbs）
    resources, src_res = _extract_resources_series_from_npz(data)
    if resources is not None:
        ts['resources'] = resources
        ts['resources_source'] = src_res

    # ★ allocated_prbs：从 allocated_prbs 求和，单独存成 allocated_prbs_sum
    alloc_sum, src_alloc = _extract_alloc_sum_series_from_npz(data)
    if alloc_sum is not None:
        ts['allocated_prbs_sum'] = alloc_sum
        ts['allocated_prbs_source'] = src_alloc

    # SLA（可选，若没有就靠 violation 推）
    sla_key = _get_first_key_case_insensitive(data, ['SLA','sla','SLA_history','sla_history'])
    if sla_key is not None:
        ts['SLA'] = data[sla_key].astype(np.float64)

    # —— 优先级相关序列（可选）——
    for name, aliases in {
        'prio_weighted': ['prio_weighted','priority_weighted'],
        'prio_mmtc':     ['prio_mmtc'],
        'prio_embb_cbr': ['prio_embb_cbr'],
        'prio_embb_vbr': ['prio_embb_vbr'],
        'cnt_mmtc':      ['cnt_mmtc'],
        'cnt_embb_cbr':  ['cnt_embb_cbr'],
        'cnt_embb_vbr':  ['cnt_embb_vbr'],
    }.items():
        k = _get_first_key_case_insensitive(data, aliases)
        if k is not None:
            ts[name] = data[k].astype(np.float64)

    # 违规率（rolling & cumulative）
    z = _to_violation_indicator(ts)
    viol_rate_final = np.nan
    if z is not None and len(z) > 0:
        steps = np.arange(1, len(z) + 1, dtype=np.float64)
        ts['viol_rate_cum'] = np.cumsum(z) / steps
        viol_rate_final = float(ts['viol_rate_cum'][-1])
        ts['viol_rate_roll'] = (rolling_mean(z, ROLL_RATE_WIN)
                                if ROLL_RATE_WIN and len(z) >= ROLL_RATE_WIN else z)

    # 统一 SLA 为 0/1
    metrics = {}
    if 'SLA' in ts:
        sla_binary = (ts['SLA'] > 0).astype(np.float64)
        ts['SLA'] = sla_binary
    elif 'violation' in ts:
        sla_binary = (ts['violation'] <= 0).astype(np.float64)
        ts['SLA'] = sla_binary
    else:
        sla_binary = None

    if sla_binary is not None and len(sla_binary) > 0:
        metrics['sla_mean'] = float(np.mean(sla_binary))
        metrics['sla_rate'] = float(np.sum(sla_binary) / len(sla_binary))
    else:
        metrics['sla_mean'] = np.nan
        metrics['sla_rate'] = np.nan

    # 其他指标
    metrics['avg_reward'] = float(np.mean(ts['reward']))    if 'reward'    in ts else np.nan
    metrics['res_mean']   = float(np.mean(ts['resources'])) if 'resources' in ts else np.nan
    metrics['viol_total'] = float(np.sum(ts['violation']))  if 'violation' in ts else np.nan
    metrics['viol_mean']  = float(np.mean(ts['violation'])) if 'violation' in ts else np.nan
    metrics['viol_rate']  = viol_rate_final

    metrics.update(compute_eval_metrics(ts))

    # —— 优先级汇总（若存在则统计）——
    if 'prio_weighted' in ts:
        metrics['prio_weight_sum']  = float(np.sum(ts['prio_weighted']))
        metrics['prio_weight_mean'] = float(np.mean(ts['prio_weighted']))
    for k in ('prio_mmtc','prio_embb_cbr','prio_embb_vbr','cnt_mmtc','cnt_embb_cbr','cnt_embb_vbr'):
        if k in ts:
            metrics[k + '_sum'] = float(np.sum(ts[k]))

    # —— 合并训练期 CSV 的 RNN/ENV 统计（曲线的点通常比每步少）——
    if aux_csv is not None:
        if aux_csv.get('tb_steps') is not None:
            ts['tb_steps'] = aux_csv['tb_steps']
        for k_src, k_dst in [
            ('rnn_epstarts_curve', 'rnn_epstarts_curve'),
            ('rnn_seq_len_curve',  'rnn_seq_len_curve'),
            ('env_viol_mean_curve','env_viol_curve_tb'),
            ('env_prio_viol_curve','env_prio_viol_curve_tb'),
            ('env_prbs_mean_curve','env_prbs_curve_tb'),
        ]:
            if aux_csv.get(k_src) is not None:
                ts[k_dst] = aux_csv[k_src]
        ts['lstm_metrics_source'] = aux_csv.get('_csv_path')

    return metrics, ts

def merge_metrics(metrics_list):
    agg = defaultdict(list)
    for m in metrics_list:
        for k, v in m.items(): agg[k].append(v)
    return {k: float(np.nanmean(v)) for k, v in agg.items()}

def align_and_stack(series_list):
    if not series_list: return {}
    keys = sorted(set().union(*[s.keys() for s in series_list]))
    out = {}
    for k in keys:
        seqs = [s[k] for s in series_list if (k in s and isinstance(s[k], np.ndarray))]
        if not seqs: continue
        T = min(len(s) for s in seqs)
        out[k] = np.stack([s[:T] for s in seqs], axis=1)
    return out

def plot_mean_std(ax, arr, label, smooth_k=None):
    mean, std = np.mean(arr, axis=1), np.std(arr, axis=1)
    if smooth_k and len(mean) >= smooth_k:
        mean, std = rolling_mean(mean, smooth_k), rolling_mean(std, smooth_k)
        x = np.arange(smooth_k-1, smooth_k-1 + len(mean))
    else:
        x = np.arange(len(mean))
    ax.plot(x, mean, label=label)
    ax.fill_between(x, mean-std, mean+std, alpha=0.2)

def print_table(title, rows, cols):
    print(f"\n{title}")
    line = "-" * (14 + len(cols)*15)
    print(line)
    header = "Algorithm".ljust(12) + " | " + " | ".join([c.ljust(12) for c in cols])
    print(header); print(line)
    for algo, m in rows:
        cells = []
        for c in cols:
            v = m.get(c, np.nan)
            if np.isnan(v): cells.append("nan".ljust(12))
            elif c == "viol_total": cells.append(f"{v:.0f}".ljust(12))
            elif c in ("viol_rate","viol_rate_eval","sla_rate","sla_rate_eval","sla_mean"): cells.append(f"{v:.4f}".ljust(12))
            else: cells.append(f"{v:.4f}".ljust(12))
        print(algo.ljust(12) + " | " + " | ".join(cells))
    print(line)

def _linear_fit_slope(x, y):
    if x is None or y is None: return np.nan
    if len(x) < 3 or len(y) < 3: return np.nan
    x = np.asarray(x, dtype=float); y = np.asarray(y, dtype=float)
    if np.any(~np.isfinite(x)) or np.any(~np.isfinite(y)): return np.nan
    try:
        k, b = np.polyfit(x, y, 1)
        return float(k)
    except Exception:
        return np.nan

def _last_k_mean(arr, k=5):
    if arr is None or len(arr)==0: return np.nan
    k = int(min(k, len(arr)))
    return float(np.mean(arr[-k:]))

def _slice_tail(arr, eval_step):
    if arr is None or len(arr) == 0: return None
    k = int(eval_step) if eval_step is not None else 0
    if k <= 0: return arr
    k = min(k, len(arr))
    return arr[-k:]

def _safe_mean(arr):
    if arr is None or len(arr) == 0: return float('nan')
    return float(np.mean(arr))

def compute_eval_metrics(ts):
    reward = ts.get('reward')
    viol = ts.get('violation')
    sla = ts.get('SLA')
    resources = ts.get('resources')
    if sla is None and viol is not None:
        sla = (viol <= 0).astype(float)
    z = (viol > 0).astype(float) if viol is not None else None
    out = {}
    out['reward_eval_mean'] = _safe_mean(_slice_tail(reward, EVAL_STEP))
    out['viol_rate_eval']   = _safe_mean(_slice_tail(z, EVAL_STEP))
    out['sla_rate_eval']    = _safe_mean(_slice_tail(sla, EVAL_STEP))
    out['res_eval_mean']    = _safe_mean(_slice_tail(resources, EVAL_STEP))
    return out

def main():
    if SAVE_FIG: ensure_dir(OUT_DIR)
    scenarios = SCENARIOS if SCENARIOS else find_scenarios(ROOT_RESULTS_DIR)
    if not scenarios:
        print("No scenarios found."); return

    overall_agg = defaultdict(list)

    # 表格列（含优先级）
    cols = [
        "avg_reward", "viol_rate", "sla_rate", "sla_mean",
        "viol_total", "viol_mean", "res_mean",
        "reward_eval_mean", "viol_rate_eval", "sla_rate_eval", "res_eval_mean",
        "prio_weight_sum", "prio_mmtc_sum", "prio_embb_cbr_sum", "prio_embb_vbr_sum",
        "cnt_mmtc_sum", "cnt_embb_cbr_sum", "cnt_embb_vbr_sum"
    ]

    for scenario in scenarios:
        algos = ALGOS if ALGOS else find_algos(ROOT_RESULTS_DIR, scenario)
        if not algos:
            print(f"[scenario {scenario}] No algos.")
            continue

        per_algo_metrics = OrderedDict()
        per_algo_series_runs = OrderedDict()
        per_algo_lstm_stats  = OrderedDict()
        lstm_csv_missing = []

        for algo in algos:
            runs = RUNS if RUNS else find_runs(ROOT_RESULTS_DIR, scenario, algo)
            if not runs: continue

            metrics_runs, series_runs = [], []
            lstm_stats_runs = []

            for run in runs:

                data_list, paths = load_npz_by_run_envs(ROOT_RESULTS_DIR, scenario, algo, run)
                aux  = load_csv_metrics_by_run(ROOT_RESULTS_DIR, scenario, algo, run)
                if aux is None:
                    lstm_csv_missing.append((scenario, algo, run))
                if (not data_list) and aux is None:
                    continue

                if not data_list:
                    # ???npz?? CSV ?????
                    class DummyNPZ(dict):
                        files = []
                    data_list = [DummyNPZ()]

                metrics_envs, series_envs = [], []
                for data in data_list:
                    m, ts = summarize_single_run(data, aux_csv=None)
                    metrics_envs.append(m); series_envs.append(ts)

                merged = merge_metrics(metrics_envs)
                aligned = align_and_stack(series_envs)
                ts_agg = {k: np.mean(v, axis=1) for k, v in aligned.items()}
                ts_agg = _merge_aux_csv_into_ts(ts_agg, aux)

                res_src = series_envs[0].get('resources_source', 'unknown') if series_envs else 'unknown'
                any_npz = any(isinstance(d, np.lib.npyio.NpzFile) for d in data_list)
                file_hint = paths[0] if paths else ts_agg.get('lstm_metrics_source','')
                print(f"[load] scenario={scenario} algo={algo} run={run}  "
                      f"resources_source={res_src}  "
                      f"npz={'yes' if any_npz else 'no'}  "
                      f"csv={'yes' if aux is not None else 'no'}  "
                      f"env_files={len(paths)}  file={file_hint}")
                metrics_runs.append(merged); series_runs.append(ts_agg)

                # ?? LSTM ???????+???
                steps = ts_agg.get('tb_steps')
                seq   = ts_agg.get('rnn_seq_len_curve')
                eps   = ts_agg.get('rnn_epstarts_curve')
                lstm_stats_runs.append({
                    'seq_last_mean': _last_k_mean(seq, 5),
                    'epstarts_mean': float(np.mean(eps)) if eps is not None and len(eps)>0 else np.nan,
                    'seq_slope': _linear_fit_slope(steps, seq),
                    'steps_last': steps[-1] if steps is not None and len(steps)>0 else np.nan
                })


            if not metrics_runs:
                continue

            merged = merge_metrics(metrics_runs)
            per_algo_metrics[algo] = merged
            per_algo_series_runs[algo] = series_runs
            # 合并 LSTM 统计
            if lstm_stats_runs:
                per_algo_lstm_stats[algo] = {
                    'seq_last_mean': float(np.nanmean([s['seq_last_mean'] for s in lstm_stats_runs])),
                    'epstarts_mean': float(np.nanmean([s['epstarts_mean'] for s in lstm_stats_runs])),
                    'seq_slope':     float(np.nanmean([s['seq_slope']     for s in lstm_stats_runs])),
                    'steps_last':    float(np.nanmax ([s['steps_last']    for s in lstm_stats_runs])),
                }

            overall_agg[algo].append(merged)

        # —— 场景控制台表格 —— 
        if per_algo_metrics:
            rows = list(per_algo_metrics.items())
            print_table(f"=== Scenario {scenario} — Summary ===", rows, cols)

        # —— 场景 LSTM 收敛文字摘要 —— 
        if per_algo_lstm_stats:
            print("\n=== Scenario {} — LSTM Training Summary (from CSV) ===".format(scenario))
            line = "-" * 74
            print(line)
            print("Algorithm    | seq_len_last5_avg | seq_len_slope/step | epstarts_mean | steps_seen")
            print(line)
            for algo, s in per_algo_lstm_stats.items():
                print(
                    f"{algo.ljust(12)} | "
                    f"{(s['seq_last_mean'] if np.isfinite(s['seq_last_mean']) else np.nan):>16.2f} | "
                    f"{(s['seq_slope'] if np.isfinite(s['seq_slope']) else np.nan):>17.4e} | "
                    f"{(s['epstarts_mean'] if np.isfinite(s['epstarts_mean']) else np.nan):>13.3f} | "
                    f"{(int(s['steps_last']) if np.isfinite(s['steps_last']) else 'nan'):>10}"
                )
            print(line)
        if lstm_csv_missing:
            miss_str = ", ".join([f"(sc{sc}, {al}, run{r})" for sc, al, r in lstm_csv_missing])
            print(f"\n[hint] No LSTM CSV metrics for: {miss_str}\n"
                  f"       若要绘制 rnn/* 曲线，请在训练脚本中启用 TBMetricsCallback 并写出 *_runX_metrics.csv。")

        # —— 绘图 —— #
        if per_algo_series_runs and SAVE_FIG:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            # ★ 这里改为 9 张子图
            fig, axs = plt.subplots(9, 1, figsize=FIGSIZE, constrained_layout=True)
            ax_map = {
                'reward': axs[0],
                'violation': axs[1],
                'resources': axs[2],            # 只画 npz["resources"]
                'allocated_prbs_sum': axs[3],   # 新增：allocated_prbs 的和
                'viol_rate_roll': axs[4],
                'viol_rate_cum': axs[5],
                'prio_weighted': axs[6],
                'rnn_epstarts_curve': axs[7],
                'rnn_seq_len_curve':  axs[8],
            }

            for algo, series_runs in per_algo_series_runs.items():
                if SHOW_BANDS and len(series_runs) > 1:
                    aligned = align_and_stack(series_runs)
                    # 明确指定要画的 key，避免依赖前 N 个切片
                    main_keys = [
                        'reward', 'violation',
                        'resources', 'allocated_prbs_sum',
                        'viol_rate_roll', 'viol_rate_cum',
                        'prio_weighted'
                    ]
                    for k in main_keys:
                        if k in aligned and k in ax_map:
                            if k.startswith("viol_rate"):
                                smooth_k = 0
                            elif k == 'resources' and not SMOOTH_RESOURCES:
                                smooth_k = 0
                            else:
                                smooth_k = SMOOTH_WINDOW
                            plot_mean_std(ax_map[k], aligned[k], label=algo, smooth_k=smooth_k)

                    # LSTM 两张：用代表 run 的 tb_steps 做横轴
                    idx = 0 if REPRESENTATIVE_RUN_FOR_CURVE is None else \
                          max(0, min(REPRESENTATIVE_RUN_FOR_CURVE, len(series_runs)-1))
                    ts = series_runs[idx]
                    if 'tb_steps' in ts:
                        if 'rnn_epstarts_curve' in ts:
                            ax_map['rnn_epstarts_curve'].plot(ts['tb_steps'], ts['rnn_epstarts_curve'], label=algo)
                        if 'rnn_seq_len_curve' in ts:
                            ax_map['rnn_seq_len_curve'].plot(ts['tb_steps'], ts['rnn_seq_len_curve'], label=algo)
                else:
                    idx = 0 if REPRESENTATIVE_RUN_FOR_CURVE is None else \
                          max(0, min(REPRESENTATIVE_RUN_FOR_CURVE, len(series_runs)-1))
                    ts = series_runs[idx]
                    # 明确指定要画的 key
                    main_keys = [
                        'reward', 'violation',
                        'resources', 'allocated_prbs_sum',
                        'viol_rate_roll', 'viol_rate_cum'
                    ]
                    for k in main_keys:
                        if k in ts and isinstance(ts[k], np.ndarray) and k in ax_map:
                            y = ts[k]
                            if k.startswith("viol_rate"):
                                x = np.arange(len(y)); y_plot = y
                            elif k == 'resources' and not SMOOTH_RESOURCES:
                                x = np.arange(len(y)); y_plot = y
                            else:
                                x, y_plot = smooth_for_plot(y, SMOOTH_WINDOW)
                            ax_map[k].plot(x, y_plot, label=algo)
                    # 第 7 张：优先级
                    if 'prio_weighted' in ts:
                        y = ts['prio_weighted']
                        x, y_plot = smooth_for_plot(y, SMOOTH_WINDOW)
                        ax_map['prio_weighted'].plot(x, y_plot, label=f"{algo} total")
                        for k2, lab in [('prio_mmtc','mMTC'), ('prio_embb_cbr','eMBB-CBR'), ('prio_embb_vbr','eMBB-VBR')]:
                            if k2 in ts:
                                xk, yk = smooth_for_plot(ts[k2], SMOOTH_WINDOW)
                                ax_map['prio_weighted'].plot(xk, yk, label=f"{algo} {lab}", linestyle='--')
                    # LSTM 两张（使用 tb_steps 为横轴）
                    if 'tb_steps' in ts:
                        if 'rnn_epstarts_curve' in ts:
                            ax_map['rnn_epstarts_curve'].plot(ts['tb_steps'], ts['rnn_epstarts_curve'], label=algo)
                        if 'rnn_seq_len_curve' in ts:
                            ax_map['rnn_seq_len_curve'].plot(ts['tb_steps'], ts['rnn_seq_len_curve'], label=algo)

            axs[0].set_title(f"Scenario {scenario} — Reward")
