            axs[2].set_title(f"Scenario {scenario} — Resources (from npz 'resources')")
            axs[3].set_title(f"Scenario {scenario} — Allocated PRBs (sum over slices)")
            axs[4].set_title(f"Scenario {scenario} — SLA Violation Rate (rolling={ROLL_RATE_WIN})")
            axs[5].set_title(f"Scenario {scenario} — SLA Violation Rate (cumulative)")
            axs[6].set_title(f"Scenario {scenario} — Priority-weighted Violations (per-step)")
            axs[7].set_title(f"Scenario {scenario} — RNN: Episode Starts Fraction (per rollout)")
